            asset, asset.lower(), f'Close_{asset}',
        ]:
            if col in df.columns:
                return df[col]
        try:
            return df[asset]['close']
        except Exception:
            pass
        try:
            return df.xs('close', level=1, axis=1)[asset]
        except Exception:
            pass
        return None

